// src/hooks/useStatusService.ts
import { useState, useCallback } from 'react';

export function useStatusService(baseUrl: string) {
  const [status, setStatus] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const lookupStatus = useCallback(async (applicationId: string) => {
    setLoading(true);
    setError(null);
    try {
      const response = await fetch(`${baseUrl}/status/v1/applications/${applicationId}`);
      if (!response.ok) throw new Error('Application not found');
      const data = await response.json();
      setStatus(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, [baseUrl]);

  return { status, loading, error, lookupStatus };
}

